patch:
--- a/decoder.v
+++ b/decoder.v
@@ -1,9 +1,10 @@
 module decoder_3to8 (
   input [2:0] sel,
+  input enable,
   output [7:0] out
 );
   assign out = enable ? (8'b1 << sel) : 8'b0;
 endmodule

 module control_unit (
   input [2:0] opcode,
+  input en,
   output [7:0] ctrl_signals
 );

before_code:
module decoder_3to8 (
  input [2:0] sel,
  input enable,
  output [7:0] out
);
  assign out = enable ? (8'b1 << sel) : 8'b0;
endmodule

module control_unit (
  input [2:0] opcode,
  input en,
  output [7:0] ctrl_signals
);
  decoder_3to8 dec_inst (
    .sel(opcode),
    .out(ctrl_signals)
  );
endmodule

after_code:
module decoder_3to8 (
  input [2:0] sel,
  input enable,
  output [7:0] out
);
  assign out = enable ? (8'b1 << sel) : 8'b0;
endmodule

module control_unit (
  input [2:0] opcode,
  input en,
  output [7:0] ctrl_signals
);
  decoder_3to8 dec_inst (
    .sel(opcode),
    .enable(en),
    .out(ctrl_signals)
  );
endmodule
